// Variable scalaire
let Threshold = 10;
let TimeWindow = 2h;

SecurityEvent
| where TimeGenerated > ago(TimeWindow)
| where EventID == 4625
| summarize Count=count() by Account
| where Count > Threshold

// Fonction inline
let IsAdmin = (account:string) {
    account in~ ("Administrator", "Domain Admins", "sysadmin")
};

SecurityEvent
| where IsAdmin(Account)

// Fonction avec calcul
let SeverityScore = (failures:long, targets:long) {
    failures * 0.5 + targets * 2.0
};

// Lambda (fonction anonyme)
let Classify = (score:real) {
    iff(score > 10, "Critical", iff(score > 5, "High", "Low"))
};
```

Dans Microsoft Sentinel, les fonctions KQL peuvent être sauvegardées et réutilisées :

```kql
// Fonction sauvegardée comme "GetSuspiciousLogins"
// Dans Sentinel : Logs → Fonctions → Enregistrer
// Exemple de fonction réutilisable
let GetSuspiciousLogins = (timeWindow:timespan, failThreshold:int) {
    SecurityEvent
    | where TimeGenerated > ago(timeWindow)
    | where EventID == 4625
    | summarize Failures=count() by Account, IpAddress
    | where Failures > failThreshold
    | sort by Failures desc
};

// Appel de la fonction
GetSuspiciousLogins(4h, 5)

// Fonctions enrichissement
let EnrichWithGeoIP = (ipColumn:string) {
    SigninLogs
    | extend Country = tostring(LocationDetails.countryOrRegion)
    | extend City    = tostring(LocationDetails.city)
};
```
